// Validate request and prepare SSH command
const body = $json.body || {};
const mode = body.mode || 'dry-run';
const roots = body.roots || ['/Users/m2ultra', '/Volumes/GOD_PRIMARY', '/Volumes/ARCHIVE1', '/Volumes/ARCHIVE2'];
const device = body.device || 'GOD';
const timestamp = new Date().toISOString();

const rootsArg = roots.join(',');
const applyFlag = mode === 'apply' ? '--apply' : '';
const command = `cd ~/noizy.ai && ./tools/claudecode-git-repair.sh --roots ${rootsArg} ${applyFlag}`;

return [{
  json: {
    mode,
    device,
    roots,
    command,
    timestamp,
    status: 'prepared'
  }
}];

const data = $json;
const gabrielSays = data.message?.content || 'Gabriel offline.';

return [{
  json: {
    status: data.mode === 'apply' ? 'approval_requested' : 'dry_run_ready',
    mode: data.mode,
    device: data.device,
    command: data.command,
    roots: data.roots,
    gabriel_says: gabrielSays,
    message: data.mode === 'apply' 
      ? 'Approval posted to Slack. Run the command on GOD after approval.'
      : 'Dry-run command ready. Run on GOD to see diagnostics without changes.',
    next_step: `SSH into ${data.device} and run: ${data.command}`
  }
}];
